import React, { useState } from 'react';

// Sample product data (mocked for now)
const products = [
  {
    id: 1,
    name: 'Ajmal Fragrance Mist Perfume Gift Set',
    price: 502,
    originalPrice: 899,
    discount: 44,
    image: 'https://cdn.blinkit.com/image1.jpg',
    delivery: '8 MINS',
    volume: '4 x 50 ml',
  },
  {
    id: 2,
    name: 'AND Ethereal Dreamer EDP & Pretty Vogue',
    price: 599,
    originalPrice: 1500,
    discount: 60,
    image: 'https://cdn.blinkit.com/image2.jpg',
    delivery: '8 MINS',
    volume: '1 pack',
  },
  // Add more products as needed
];

function App() {
  const [cart, setCart] = useState([]);

  const addToCart = (product) => {
    setCart((prev) => [...prev, product]);
  };

  return (
    <div style={{ fontFamily: 'sans-serif', background: '#f8f8f8', minHeight: '100vh' }}>
      <header style={{ background: '#fff', padding: '16px 32px', boxShadow: '0 2px 8px #eee', display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <span style={{ fontWeight: 'bold', fontSize: 28, color: '#6cc24a' }}>blinkit</span>
        <div style={{ fontSize: 18 }}>Cart: {cart.length} item(s)</div>
      </header>
      <main style={{ padding: 32 }}>
        <h2>Buy Bath & Beauty Gifts Online</h2>
        <div style={{ display: 'flex', gap: 24, flexWrap: 'wrap' }}>
          {products.map((product) => (
            <div key={product.id} style={{ background: '#fff', borderRadius: 12, boxShadow: '0 2px 8px #eee', width: 240, padding: 16, display: 'flex', flexDirection: 'column', alignItems: 'center' }}>
              <img src={product.image} alt={product.name} style={{ width: 180, height: 120, objectFit: 'cover', borderRadius: 8 }} />
              <div style={{ marginTop: 12, fontWeight: 600 }}>{product.name}</div>
              <div style={{ color: '#888', fontSize: 14 }}>{product.volume}</div>
              <div style={{ margin: '8px 0', fontSize: 16 }}>
                <span style={{ fontWeight: 700 }}>₹{product.price}</span>
                <span style={{ textDecoration: 'line-through', color: '#aaa', marginLeft: 8 }}>₹{product.originalPrice}</span>
                <span style={{ color: '#6cc24a', marginLeft: 8 }}>{product.discount}% OFF</span>
              </div>
              <div style={{ color: '#6cc24a', fontSize: 13 }}>{product.delivery}</div>
              <button onClick={() => addToCart(product)} style={{ marginTop: 12, background: '#6cc24a', color: '#fff', border: 'none', borderRadius: 6, padding: '8px 24px', cursor: 'pointer', fontWeight: 600 }}>ADD</button>
            </div>
          ))}
        </div>
      </main>
    </div>
  );
}

export default App;
